(function() {
    // ১. বার্তার তালিকা (বট যা যা বলবে)
    const messages = [
        "Hi,l'am Bot.    ",
        "My Name Axiom",
        "My Developer Company Name OpenDeta",
        "I'am Steel Updating",
        "My developer is still giving me updates…",
        "How are you today?",
        "I am learning how to chat like a human! 😉",
        "Okay, I'm going to take a small break now. Bye!",
    ];

    let currentIndex = 0;

    // ২. মেসেজ পাঠানোর মেইন ফাংশন
    function sendMessage(text) {
        const inputField = document.querySelector('div[contenteditable="true"]') || 
                           document.querySelector('textarea');

        if (inputField) {
            inputField.focus();

            // মানুষের মতো টাইপিং সিমুলেশন (সরাসরি টেক্সট বসানো)
            if (inputField.tagName === 'DIV') {
                inputField.innerText = text;
            } else {
                inputField.value = text;
            }

            // ইনপুট ইভেন্ট (যাতে সেন্ড বাটন অ্যাক্টিভ হয়)
            inputField.dispatchEvent(new Event('input', { bubbles: true }));

            // ৩. সেন্ড বাটনে ক্লিক (১ সেকেন্ড ডিলে যাতে ন্যাচারাল লাগে)
            setTimeout(() => {
                const sendBtn = document.querySelector('button[aria-label*="Send"]') || 
                                document.querySelector('button[aria-label*="পাঠান"]') ||
                                document.querySelector('button.send-button');

                if (sendBtn && !sendBtn.disabled) {
                    sendBtn.click();
                    console.log("Sent: " + text);

                    // ৪. পরবর্তী মেসেজের জন্য ৫ সেকেন্ড অপেক্ষা (Loop)
                    currentIndex++;
                    if (currentIndex < messages.length) {
                        setTimeout(() => {
                            sendMessage(messages[currentIndex]);
                        }, 9000); // আপনার ৫ সেকেন্ডের বিরতি
                    } else {
                        console.log("চ্যাটিং শেষ! মিশন সাকসেসফুল। 🎉");
                    }
                } else {
                    // এন্টার কী ব্যাকআপ
                    inputField.dispatchEvent(new KeyboardEvent('keydown', {
                        bubbles: true, keyCode: 13, key: 'Enter'
                    }));

                    currentIndex++;
                    if (currentIndex < messages.length) {
                        setTimeout(() => sendMessage(messages[currentIndex]), 9000);
                    }
                }
            }, 1500);
        } else {
            console.log("ইনপুট বক্স পাওয়া যায়নি! জেমিনি কি লোড হয়েছে?");
        }
    }

    // ৫. প্রথম মেসেজ দিয়ে শুরু করা
    console.log("বট চ্যাটিং শুরু করছে...");
    sendMessage(messages[currentIndex]);

})();
